import React from 'react';
import { internships } from '../../data/mockData';
import InternshipCard from '../../components/InternshipCard';

export default function BrowseInternships() {
  return (
    <div className="page-enter">
      <h1 className="dashboard-title">Browse Internships</h1>
      <div style={{ columns: 3, gap: 'var(--space-md)' }}>
        {internships.map(i => (
          <div key={i.id} style={{ marginBottom: 'var(--space-md)', breakInside: 'avoid' }}>
            <InternshipCard internship={i} />
          </div>
        ))}
      </div>
    </div>
  );
}
